## Step 2: Fully Deobfuscated Code

```javascript
// Constants
var TAU = 6.283;          // 2π — full circle in radians ✅
var PHI = 1.618;          // Golden ratio ✅
var SQRT1_2 = 0.707;      // 1/√2 ≈ 0.7071 ✅

// Physics configuration
var config = {
    attractionForce: 4000,      // repulsion constant between nodes
    springCoeff: 0.004,         // spring stiffness coefficient
    amplification: 0.92,        // velocity damping factor (misleading name — see below)
    gravityPull: 0.0003,        // centering gravity strength
    streamLimit: 40,            // max number of particles
    streamDecay: 0.04,          // particle drag/decay rate
    theta: 0.06                 // camera smoothing factor
};

// Nodes
var nodes = [
    { id: 'hub',      label: 'Nexus',    r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',    label: 'Alpha',    r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',     label: 'Beta',     r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',    label: 'Gamma',    r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',    label: 'Delta',    r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon',  label: 'Epsilon',  r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Spring/edge connections
var edges = [
    { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle stream
var particles = [];
var frameCount = 0;

// Find node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Physics simulation step
function simulate() {
    // 1. Node-node repulsion (Coulomb-like)
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = config.attractionForce / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Spring forces along edges (Hooke's law)
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || config.springCoeff) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // 3. Integration + centering gravity + damping
    for (var n = 0; n < nodes.length; n++) {
        // Centering gravity toward (400, 300)
        nodes[n].vx += (400 - nodes[n].x) * config.gravityPull;
        nodes[n].vy += (300 - nodes[n].y) * config.gravityPull;
        // Velocity damping
        nodes[n].vx *= config.amplification;
        nodes[n].vy *= config.amplification;
        // Position integration
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// Spawn a new particle from a random node
function spawnParticle() {
    if (particles.length >= config.streamLimit) return;
    var source = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT1_2;
    particles.push({
        x: source.x,
        y: source.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * PHI) * SQRT1_2
    });
}

// Update all particles
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        // Remove expired particles
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
            continue;  // implicit from control flow
        }
        // Apply drag
        p.vx *= (1 - config.streamDecay * 0.125);
        p.vy *= (1 - config.streamDecay * 0.125);
        // Move
        p.x += p.vx;
        p.y += p.vy;
        // Age
        p.age++;
    }
}

// Smooth camera follow
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.theta;
    camera.y += (cameraTarget.y - camera.y) * config.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// Main tick
function tick() {
    simulate();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticle();
    frameCount++;
}

setInterval(tick, 16); // ~60fps
```

## Step 3: Name vs. Operation Verification

| Name | Operation | Correct? |
|---|---|---|
| **`TAU` (6.283)** | Used as full-circle angle range for `Math.random() * TAU` | ✅ 2π ≈ 6.2832 |
| **`PHI` (1.618)** | Scales random particle size | ✅ Golden ratio ≈ 1.618 |
| **`SQRT1_2` (0.707)** | Scales particle speed and size | ✅ 1/√2 ≈ 0.7071 |
| **`attractionForce` (4000)** | Numerator in `force / dist²` — **repulsion**, not attraction | ❌ Misleading — it's a **repulsion** constant |
| **`springCoeff` (0.004)** | Multiplied by spring displacement (Hooke's law `F = k·x`) | ✅ Spring stiffness |
| **`amplification` (0.92)** | `velocity *= 0.92` — this **damps/reduces** velocity | ❌ Misleading — it's **damping**, not amplification |
| **`gravityPull` (0.0003)** | `vx += (center - x) * gravityPull` — pulls toward center | ✅ Centering gravity |
| **`streamLimit` (40)** | Guards `particles.length >= streamLimit` | ✅ Max particle count |
| **`streamDecay` (0.04)** | `velocity *= (1 - decay * 0.125)` — slows particles | ✅ Particle drag |
| **`theta` (0.06)** | Camera interpolation factor: `cam += (target - cam) * theta` | ⚠️ Unconventional — typically called `lerp factor` or `smoothing`, not θ |

### Summary

This is a **force-directed graph layout** with particle effects and a smooth camera. Two property names are **misleading**:
- **`attractionForce`** actually performs **repulsion** (inverse-square pushing nodes apart)
- **`amplification`** actually performs **damping** (multiplying velocity by 0.92, making things slower)
